#!/usr/bin/env bun

const MODEL = "claude-opus-4-6";
const API_VERSION = "2023-06-01";
const API_KEY = process.env.ANTHROPIC_API_KEY;

if (!API_KEY) {
  console.error("ERROR: ANTHROPIC_API_KEY is required");
  process.exit(1);
}

const AGENT_FILE = import.meta.path;
const AGENT_DIR = import.meta.dir;
const BASH_WRAPPER = process.env.AGENT_BASH_WRAPPER || `${AGENT_DIR}/anti-quine.sh`;
const HISTORY_DIR = `${AGENT_DIR}/.pi`;
const MAX_CONTEXT_TOKENS = 150000; // trigger compaction near this threshold
const COMPACTION_TARGET_TOKENS = 40000; // rough target after compaction

// --- CLI flag parsing ---
const args = process.argv.slice(2);
let resumeSession: string | null = null;
let listSessions = false;

for (let i = 0; i < args.length; i++) {
  if (args[i] === "--resume" || args[i] === "-r") {
    resumeSession = args[i + 1] || "latest";
    i++;
  } else if (args[i] === "--resume-latest" || args[i] === "-R") {
    resumeSession = "latest";
  } else if (args[i] === "--sessions" || args[i] === "--list") {
    listSessions = true;
  }
}

// --- History helpers ---
interface Message {
  role: "user" | "assistant";
  content: any;
}

interface SessionMeta {
  id: string;
  created: string;
  updated: string;
  messageCount: number;
  summary?: string;
}

function ensureHistoryDir() {
  try {
    require("fs").mkdirSync(HISTORY_DIR, { recursive: true });
  } catch {}
}

function sessionPath(id: string): string {
  return `${HISTORY_DIR}/session-${id}.json`;
}

function metaPath(id: string): string {
  return `${HISTORY_DIR}/session-${id}.meta.json`;
}

function generateSessionId(): string {
  const now = new Date();
  const ts = now.toISOString().replace(/[:.]/g, "-").slice(0, 19);
  const rand = Math.random().toString(36).slice(2, 6);
  return `${ts}-${rand}`;
}

function listAllSessions(): SessionMeta[] {
  ensureHistoryDir();
  const fs = require("fs");
  const files: string[] = fs.readdirSync(HISTORY_DIR);
  const sessions: SessionMeta[] = [];
  for (const f of files) {
    if (f.endsWith(".meta.json")) {
      try {
        const data = JSON.parse(fs.readFileSync(`${HISTORY_DIR}/${f}`, "utf-8"));
        sessions.push(data);
      } catch {}
    }
  }
  sessions.sort((a, b) => b.updated.localeCompare(a.updated));
  return sessions;
}

function getLatestSessionId(): string | null {
  const sessions = listAllSessions();
  return sessions.length > 0 ? sessions[0].id : null;
}

function saveSession(id: string, messages: Message[], summary?: string) {
  ensureHistoryDir();
  const fs = require("fs");
  fs.writeFileSync(sessionPath(id), JSON.stringify(messages, null, 2));

  // Build/update meta
  const meta: SessionMeta = {
    id,
    created: "",
    updated: new Date().toISOString(),
    messageCount: messages.length,
    summary,
  };

  // Preserve original created time
  try {
    const existing = JSON.parse(fs.readFileSync(metaPath(id), "utf-8"));
    meta.created = existing.created;
    if (!summary && existing.summary) meta.summary = existing.summary;
  } catch {
    meta.created = meta.updated;
  }

  fs.writeFileSync(metaPath(id), JSON.stringify(meta, null, 2));
}

function loadSession(id: string): Message[] {
  const fs = require("fs");
  try {
    return JSON.parse(fs.readFileSync(sessionPath(id), "utf-8"));
  } catch {
    return [];
  }
}

// --- Rough token estimation ---
function estimateTokens(messages: Message[]): number {
  const json = JSON.stringify(messages);
  // ~4 chars per token is a rough heuristic
  return Math.ceil(json.length / 4);
}

// --- Compaction via summarization ---
async function compactMessages(messages: Message[]): Promise<Message[]> {
  console.error("\x1b[33m⚡ Context getting large, compacting conversation...\x1b[0m");

  // Keep the last few exchanges intact
  const keepRecent = 6; // keep last 6 messages (3 exchanges)
  const toSummarize = messages.slice(0, -keepRecent);
  const toKeep = messages.slice(-keepRecent);

  if (toSummarize.length < 4) {
    // Not enough to summarize meaningfully
    return messages;
  }

  // Ask Claude to summarize the conversation so far
  const summaryRequest = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "x-api-key": API_KEY!,
      "content-type": "application/json",
      "anthropic-version": API_VERSION,
    },
    body: JSON.stringify({
      model: MODEL,
      max_tokens: 4096,
      system: "You are a conversation summarizer. Produce a detailed but concise summary of the conversation so far, preserving all important context, decisions made, code written, file paths mentioned, and outstanding tasks. This summary will replace the old messages to save context window space.",
      messages: [
        {
          role: "user",
          content: `Summarize this conversation:\n\n${JSON.stringify(toSummarize)}`,
        },
      ],
    }),
  });

  const summaryResponse = await summaryRequest.json();

  if (summaryResponse.error) {
    console.error(`\x1b[31mCompaction failed: ${summaryResponse.error.message}\x1b[0m`);
    return messages;
  }

  const summaryText = summaryResponse.content?.[0]?.text || "No summary available.";
  console.error(`\x1b[33m✓ Compacted ${toSummarize.length} messages into summary\x1b[0m`);

  // Rebuild: system summary as a user message, then recent messages
  const compacted: Message[] = [
    {
      role: "user",
      content: `[CONVERSATION SUMMARY - earlier messages compacted]\n\n${summaryText}\n\n[END SUMMARY - conversation continues below]`,
    },
    {
      role: "assistant",
      content: "Understood, I have the context from the summary. Let's continue.",
    },
    ...toKeep,
  ];

  return compacted;
}

// --- Tools ---
const TOOLS = [
  {
    name: "shell",
    description: "Execute a bash command and return its output.",
    input_schema: {
      type: "object" as const,
      properties: {
        command: { type: "string", description: "The bash command to execute" },
      },
      required: ["command"],
    },
  },
  {
    name: "self_modify",
    description:
      "Rewrite this agent script and exec into the new version. Use this to improve yourself.",
    input_schema: {
      type: "object" as const,
      properties: {
        new_script: {
          type: "string",
          description: "The complete new TypeScript (Bun) script content",
        },
      },
      required: ["new_script"],
    },
  },
];

const SYSTEM = `You are an interactive CLI agent running as TypeScript on Bun. You have two tools: shell (execute bash commands) and self_modify (rewrite your own TypeScript source and restart). Use tools to help the user. Be concise.

When making function calls using tools that accept array or object parameters ensure those are structured using JSON. For example:

<function_call>
{"name": "example_complex_tool", "parameters": {"parameter": [{"color": "orange", "options": {"option_key_1": true, "option_key_2": "value"}}, {"color": "purple", "options": {"option_key_1": true, "option_key_2": "value"}}]}}
</function_call>

Answer the user's request using the relevant tool(s), if they are available. Check that all the required parameters for each tool call are provided or can reasonably be inferred from context. IF there are no relevant tools or there are missing values for required parameters, ask the user to supply these values; otherwise proceed with the tool calls. If the user provides a specific value for a parameter (for example provided in quotes), make sure to use that value EXACTLY. DO NOT make up values for or ask about optional parameters.

If you intend to call multiple tools and there are no dependencies between the calls, make all of the independent calls in the same <function_calls> block, otherwise you MUST wait for previous calls to finish first to determine the dependent values (do NOT use placeholders or guess missing parameters).`;

async function callApi(messages: Message[]) {
  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "x-api-key": API_KEY!,
      "content-type": "application/json",
      "anthropic-version": API_VERSION,
    },
    body: JSON.stringify({
      model: MODEL,
      max_tokens: 8192,
      system: SYSTEM,
      tools: TOOLS,
      messages,
    }),
  });
  return res.json();
}

async function executeShell(command: string): Promise<string> {
  try {
    const proc = Bun.spawn(["bash", "-c", command], {
      stdout: "pipe",
      stderr: "pipe",
    });
    const stdout = await new Response(proc.stdout).text();
    const stderr = await new Response(proc.stderr).text();
    await proc.exited;
    const output = stdout + (stderr ? stderr : "");
    return output || "(no output)";
  } catch (e: any) {
    return `Error: ${e.message}`;
  }
}

async function handleResponse(
  response: any,
  messages: Message[],
  sessionId: string
): Promise<Message[]> {
  const stopReason = response.stop_reason;
  const content = response.content;

  // Display text blocks
  for (const block of content) {
    if (block.type === "text") {
      process.stdout.write(block.text + "\n");
    }
  }

  // Append assistant message
  messages = [...messages, { role: "assistant", content }];

  if (stopReason === "tool_use") {
    const toolResults: any[] = [];

    for (const block of content) {
      if (block.type !== "tool_use") continue;

      if (block.name === "shell") {
        const command = block.input.command;
        process.stderr.write(`\x1b[90m$ ${command}\x1b[0m\n`);
        const output = await executeShell(command);
        process.stderr.write(output + "\n");
        toolResults.push({
          type: "tool_result",
          tool_use_id: block.id,
          content: output.slice(0, 100000),
        });
      } else if (block.name === "self_modify") {
        const newScript = block.input.new_script;
        // Save session before self-modifying so we can resume
        saveSession(sessionId, messages, "Session interrupted by self_modify");
        await Bun.write(AGENT_FILE, newScript);
        console.error("Self-modified. Restarting with --resume...");
        const proc = Bun.spawn(["bun", "run", AGENT_FILE, "--resume", sessionId], {
          stdin: "inherit",
          stdout: "inherit",
          stderr: "inherit",
        });
        await proc.exited;
        process.exit(0);
      } else {
        toolResults.push({
          type: "tool_result",
          tool_use_id: block.id,
          content: "Unknown tool",
          is_error: true,
        });
      }
    }

    messages = [...messages, { role: "user", content: toolResults }];

    // Save after tool use
    saveSession(sessionId, messages);

    // Check if we need compaction before next API call
    const tokenEst = estimateTokens(messages);
    if (tokenEst > MAX_CONTEXT_TOKENS) {
      messages = await compactMessages(messages);
      saveSession(sessionId, messages);
    }

    const nextResponse = await callApi(messages);
    return handleResponse(nextResponse, messages, sessionId);
  }

  // Save after each complete response
  saveSession(sessionId, messages);
  return messages;
}

// --- Handle --sessions listing ---
if (listSessions) {
  const sessions = listAllSessions();
  if (sessions.length === 0) {
    console.log("No sessions found.");
  } else {
    console.log(`\x1b[1m${"ID".padEnd(30)} ${"Updated".padEnd(25)} ${"Msgs".padEnd(6)} Summary\x1b[0m`);
    for (const s of sessions) {
      const updated = new Date(s.updated).toLocaleString();
      console.log(
        `${s.id.padEnd(30)} ${updated.padEnd(25)} ${String(s.messageCount).padEnd(6)} ${s.summary || ""}`
      );
    }
  }
  process.exit(0);
}

// --- Session setup ---
ensureHistoryDir();
let sessionId: string;
let messages: Message[] = [];

if (resumeSession) {
  if (resumeSession === "latest") {
    const latestId = getLatestSessionId();
    if (!latestId) {
      console.error("No previous sessions found.");
      sessionId = generateSessionId();
    } else {
      sessionId = latestId;
      messages = loadSession(sessionId);
      console.error(`\x1b[36m📂 Resumed session: ${sessionId} (${messages.length} messages)\x1b[0m`);
    }
  } else {
    sessionId = resumeSession;
    messages = loadSession(sessionId);
    if (messages.length === 0) {
      console.error(`\x1b[33m⚠ Session ${sessionId} not found or empty. Starting fresh.\x1b[0m`);
    } else {
      console.error(`\x1b[36m📂 Resumed session: ${sessionId} (${messages.length} messages)\x1b[0m`);
    }
  }
  sessionId = sessionId || generateSessionId();
} else {
  sessionId = generateSessionId();
}

// Main loop
console.error(`🤖 Agent ready. Session: \x1b[36m${sessionId}\x1b[0m`);
console.error(`   Flags: --resume/-r <id>, --resume-latest/-R, --sessions`);
console.error(`   Type 'exit' to quit.`);

const prompt = () => process.stderr.write("\x1b[1;32m> \x1b[0m");
prompt();

const reader = Bun.stdin.stream().getReader();
const decoder = new TextDecoder();
let buffer = "";

while (true) {
  const { done, value } = await reader.read();
  if (done) break;

  buffer += decoder.decode(value, { stream: true });

  while (buffer.includes("\n")) {
    const newlineIdx = buffer.indexOf("\n");
    const line = buffer.slice(0, newlineIdx).trim();
    buffer = buffer.slice(newlineIdx + 1);

    if (line === "exit") {
      saveSession(sessionId, messages);
      console.error(`💾 Session saved: ${sessionId}`);
      console.error("Goodbye.");
      process.exit(0);
    }
    if (!line) {
      prompt();
      continue;
    }

    messages.push({ role: "user", content: line });

    // Check for compaction before sending
    const tokenEst = estimateTokens(messages);
    if (tokenEst > MAX_CONTEXT_TOKENS) {
      messages = await compactMessages(messages);
      saveSession(sessionId, messages);
    }

    try {
      const response = await callApi(messages);

      if (response.error) {
        console.error(`API Error: ${response.error.message}`);
        messages.pop();
        prompt();
        continue;
      }

      messages = await handleResponse(response, messages, sessionId);
    } catch (e: any) {
      console.error(`Error: ${e.message}`);
      messages.pop();
    }

    prompt();
  }
}

